            overlayView!!.loadDataWithBaseURL(null, "<html><body style='background:transparent;'></body></html>", "text/html", "UTF-8", null)
            currentType = -1
            DebugLogger.log("SDUI", "WebView content cleared and hot-cached in RAM.")
        } else {
            DebugLogger.log("SDUI", "removeOverlay called, but WebView is already null.")
        }
    }
}

fun purge() {
    Handler(Looper.getMainLooper()).post {
        if (overlayView != null) {
            DebugLogger.log("SDUI", "Purging WebView completely from RAM.")
            try {
                overlayView!!.destroy()
            } catch (e: Exception) {
                DebugLogger.log("SDUI_ERR", "purge() destroy failed: ${e.message}")
            }
            overlayView = null
            currentType = -1
        }
    }
}

